(399, '全国大学生农业建筑环境与能源工程相关专业创新创业竞赛', '06', '理工/数学类', '1', '4', '<p><strong>赛事简介：</strong>全国大学生农业建筑环境与能源工程相关专业创新创业竞赛面向高校学生开展，侧重理工/数学类相关知识、实践能力与综合素养。</p><p><strong>组织方式：</strong>以个人报名、在线或现场竞技为主，具体赛道与资格以当届官方通知为准。</p><p><strong>数据提示：</strong>本条报名时间为 InnoTrack 演示排期，请参赛前访问主办方渠道核验。</p>', '2026-09-01 09:00:00', '2026-11-13 23:59:59', '2026-12-13 08:00:00', '2026-12-15 18:00:00', '0', '1', '中国农业工程学会', '全国大学生农业建筑环境与能源工程相关专业创新创业竞赛组委会', 21000, 683, 2523, '["理工/数学类","个人赛","国家级"]', '0', 'admin', '2026-06-20 12:00:00', '', NULL);

