-- 导入后核验（预期：新增比赛 100、经验帖 20、种子复盘 216）
SELECT category, category_name, COUNT(*) AS added_competitions
FROM competition WHERE competition_id BETWEEN 300 AND 399
GROUP BY category, category_name ORDER BY category;
SELECT COUNT(*) AS added_experiences FROM competition_experience WHERE experience_id BETWEEN 100 AND 119;
SELECT COUNT(*) AS added_retrospects FROM competition_retrospect WHERE retrospect_id BETWEEN 1000 AND 1215;
SELECT comp_id, COUNT(*) AS retrospect_count
FROM competition_retrospect WHERE retrospect_id BETWEEN 1000 AND 1215
GROUP BY comp_id HAVING COUNT(*) <> 2;

